   590→	c.logger.Info("write block started", "mint", mint, "maxt", maxt, "ulid", uid)
   591→
   592→	meta := &BlockMeta{
   593→		ULID:    uid,
   594→		MinTime: mint,
   595→		MaxTime: maxt,
