  1175→func (db *DB) run(ctx context.Context) {
  1176→	defer close(db.donec)
  1177→
  1178→	backoff := time.Duration(0)
  1179→
  1180→	for {
  1181→		select {
  1182→		case <-db.stopc:
  1183→			return
  1184→		case <-time.After(backoff):
  1185→		}
  1186→
  1187→		select {
  1188→		case <-time.After(db.opts.BlockReloadInterval):
  1189→			db.cmtx.Lock()
  1190→			if err := db.reloadBlocks(); err != nil {
  1191→				db.logger.Error("reloadBlocks", "err", err)
  1192→			}
  1193→			db.cmtx.Unlock()
  1194→
  1195→			select {
  1196→			case db.compactc <- struct{}{}:
  1197→			default:
  1198→			}
  1199→			// We attempt mmapping of head chunks regularly.
  1200→			db.head.mmapHeadChunks()
  1201→
  1202→			numStaleSeries, numSeries := db.Head().NumStaleSeries(), db.Head().NumSeries()
  1203→			if db.autoCompact && numSeries > 0 && db.opts.staleSeriesCompactionThreshold.Load() > 0 {
  1204→				staleSeriesRatio := float64(numStaleSeries) / float64(numSeries)
  1205→				if staleSeriesRatio >= db.opts.staleSeriesCompactionThreshold.Load() {
  1206→					nextCompactionIsSoon := false
  1207→					if !db.lastHeadCompactionTime.IsZero() {
  1208→						compactionInterval := time.Duration(db.head.chunkRange.Load()) * time.Millisecond
  1209→						nextEstimatedCompactionTime := db.lastHeadCompactionTime.Add(compactionInterval)
  1210→						if time.Now().Add(10 * time.Minute).After(nextEstimatedCompactionTime) {
  1211→							// Next compaction is starting within next 10 mins.
  1212→							nextCompactionIsSoon = true
  1213→						}
  1214→					}
  1215→
  1216→					if !nextCompactionIsSoon {
  1217→						if err := db.CompactStaleHead(); err != nil {
  1218→							db.logger.Error("immediate stale series compaction failed", "err", err)
  1219→						}
  1220→					}
  1221→				}
  1222→			}
  1223→
  1224→		case <-db.compactc:
  1225→			db.metrics.compactionsTriggered.Inc()
  1226→
  1227→			db.autoCompactMtx.Lock()
  1228→			if db.autoCompact {
  1229→				if err := db.Compact(ctx); err != nil {
  1230→					db.logger.Error("compaction failed", "err", err)
  1231→					backoff = exponential(backoff, 1*time.Second, 1*time.Minute)
  1232→				} else {
  1233→					backoff = 0
  1234→				}
  1235→			} else {
  1236→				db.metrics.compactionsSkipped.Inc()
  1237→			}
  1238→			db.autoCompactMtx.Unlock()
  1239→		case <-db.stopc:
  1240→			return
  1241→		}
  1242→	}
  1243→}
